css:
/*
禁二传/商用
作者：再活五分钟
*/

@import url("https://fontsapi.zeoseven.com/25/main/result.css");

/* 全局字体 */
:not([class*="fa-"]):not(.fas):not(.far):not(.fal):not(.fab):not(.fa) {
    font-family: "WenQuanYi Micro Hei";
    font-weight: 400;
}

/* 图标字体 */
[class*="fa-"], .fas, .far, .fal, .fab, .fa {
    font-family: "Font Awesome 6 Free", "Font Awesome 5 Free" !important;
}

/* 隐藏滚动条 */
::-webkit-scrollbar {
  display: none;
}

.mes_text {
  text-align: justify;
}

/* 消息框文字宽度 */
.mes_block .ch_name,
.mes_block .mes_text {
    width: 100%;
    box-sizing: border-box;
    margin: 0;
    padding-left: 0;
    padding-right: 0;
}

.mes_block .mes_text {
    padding-top: calc(var(--mainFontSize) * 0.8);
}

.drawer-content.openDrawer {
    max-height: calc(100dvh - var(--topBarBlockSize));
}

#left-nav-panel,
#right-nav-panel {
    height: 100dvh;
    max-height: 100dvh;
}

@media (max-width: 600px) {
    #right-nav-panel {
        max-height: calc(100dvh - var(--topBarBlockSize));
    }
}

body *:not(#send_form) {
  border: none !important;
  outline: none !important;
  box-shadow: none !important;
  filter: none !important;
}

#sheld {
    top: var(--bottomFormBlockSize);
    height: calc(100dvh - var(--bottomFormBlockSize));
    max-height: calc(100dvh - var(--bottomFormBlockSize));
    min-height: calc(100dvh - var(--bottomFormBlockSize));
}

/* 消息容器布局 */
.mes {
    display: flex !important;
    flex-direction: column !important;
    align-items: flex-start !important;
    gap: 5px;
}

.mes[is_user="true"] {
    align-items: flex-end !important;
}

/* 头像容器布局 */
.mes .mesAvatarWrapper {
    display: flex;
    flex-direction: row;
    align-items: center;
    gap: 12px;
    padding: 0 10px;
    position: relative !important;
    z-index: 3 !important;
    margin-top: -40px !important;
    margin-bottom: 10px !important;
    width: auto !important;
    flex-shrink: 0 !important;
    padding-bottom: 25px !important;
}

.mes[is_user="true"] .mesAvatarWrapper {
    flex-direction: row-reverse;
}

/* 昵称与时间戳定位 */
.mes .mes_block {
    position: relative !important;
    width: 100%;
    padding-bottom: 3.8em !important;
    padding-left: 10px !important;
    padding-right: 10px !important;
}

.mes .ch_name .name_text {
    font-size: 1.2em !important;
    font-weight: bold !important;
}

.mes .ch_name .timestamp {
    display: block !important;
    position: static !important;
    font-size: 1.2em !important;
    font-weight: normal !important;
    opacity: 0.75;
}

/* 消息框整体样式 */
#chat .mes {
    width: 92% !important;
    max-width: 100% !important;
    margin: 25px auto 35px !important;
    position: relative;
    background: #FFFFFF !important;
    border: none !important;
    box-shadow: 0 6px 20px rgba(0, 0, 0, 0.12) !important;
    border-radius: 12px !important;
    overflow: visible !important;
    padding-top: 160px !important;
    padding-bottom: 25px !important;
    display: flex;
    flex-direction: column;
    align-items: center;
}

/* 头像样式 */
#chat .mes .avatar {
    --avatar-size: 65px;
    width: var(--avatar-size) !important;
    height: var(--avatar-size) !important;
    min-width: var(--avatar-size) !important;
    min-height: var(--avatar-size) !important;
    position: relative !important;
    flex-shrink: 0 !important;
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.2) !important;
    border-radius: 0 !important;
    border: none !important;
    overflow: visible !important;
    background: #FF6B9D !important;
    transform: rotate(-30deg);
    -webkit-mask-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 100 100' xmlns='http://www.w3.org/2000/svg'%3E%3Cdefs%3E%3Cpath id='heart' d='M0,-8 C-4,-13 -8,-13 -10,-8 C-12,-3 -8,2 0,8 C8,2 12,-3 10,-8 C8,-13 4,-13 0,-8 Z'/%3E%3C/defs%3E%3Cuse href='%23heart' transform='translate(50,30) scale(2.2) rotate(0)' fill='white'/%3E%3Cuse href='%23heart' transform='translate(70,50) scale(2.2) rotate(90)' fill='white'/%3E%3Cuse href='%23heart' transform='translate(50,70) scale(2.2) rotate(180)' fill='white'/%3E%3Cuse href='%23heart' transform='translate(30,50) scale(2.2) rotate(270)' fill='white'/%3E%3Ccircle cx='50' cy='50' r='6' fill='white'/%3E%3C/svg%3E");
    mask-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 100 100' xmlns='http://www.w3.org/2000/svg'%3E%3Cdefs%3E%3Cpath id='heart' d='M0,-8 C-4,-13 -8,-13 -10,-8 C-12,-3 -8,2 0,8 C8,2 12,-3 10,-8 C8,-13 4,-13 0,-8 Z'/%3E%3C/defs%3E%3Cuse href='%23heart' transform='translate(50,30) scale(2.2) rotate(0)' fill='white'/%3E%3Cuse href='%23heart' transform='translate(70,50) scale(2.2) rotate(90)' fill='white'/%3E%3Cuse href='%23heart' transform='translate(50,70) scale(2.2) rotate(180)' fill='white'/%3E%3Cuse href='%23heart' transform='translate(30,50) scale(2.2) rotate(270)' fill='white'/%3E%3Ccircle cx='50' cy='50' r='6' fill='white'/%3E%3C/svg%3E");
    -webkit-mask-size: 100% 100%;
    mask-size: 100% 100%;
    -webkit-mask-repeat: no-repeat;
    mask-repeat: no-repeat;
}

#chat .mes .avatar::before {
    content: '';
    position: absolute;
    top: -3px;
    left: -3px;
    right: -3px;
    bottom: -3px;
    background: #2E7D32;
    z-index: -1;
    -webkit-mask-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 100 100' xmlns='http://www.w3.org/2000/svg'%3E%3Cdefs%3E%3Cpath id='heart' d='M0,-8 C-4,-13 -8,-13 -10,-8 C-12,-3 -8,2 0,8 C8,2 12,-3 10,-8 C8,-13 4,-13 0,-8 Z'/%3E%3C/defs%3E%3Cuse href='%23heart' transform='translate(50,29) scale(2.35) rotate(0)' fill='white'/%3E%3Cuse href='%23heart' transform='translate(71,50) scale(2.35) rotate(90)' fill='white'/%3E%3Cuse href='%23heart' transform='translate(50,71) scale(2.35) rotate(180)' fill='white'/%3E%3Cuse href='%23heart' transform='translate(29,50) scale(2.35) rotate(270)' fill='white'/%3E%3Ccircle cx='50' cy='50' r='7' fill='white'/%3E%3C/svg%3E");
    mask-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 100 100' xmlns='http://www.w3.org/2000/svg'%3E%3Cdefs%3E%3Cpath id='heart' d='M0,-8 C-4,-13 -8,-13 -10,-8 C-12,-3 -8,2 0,8 C8,2 12,-3 10,-8 C8,-13 4,-13 0,-8 Z'/%3E%3C/defs%3E%3Cuse href='%23heart' transform='translate(50,29) scale(2.35) rotate(0)' fill='white'/%3E%3Cuse href='%23heart' transform='translate(71,50) scale(2.35) rotate(90)' fill='white'/%3E%3Cuse href='%23heart' transform='translate(50,71) scale(2.35) rotate(180)' fill='white'/%3E%3Cuse href='%23heart' transform='translate(29,50) scale(2.35) rotate(270)' fill='white'/%3E%3Ccircle cx='50' cy='50' r='7' fill='white'/%3E%3C/svg%3E");
    -webkit-mask-size: 100% 100%;
    mask-size: 100% 100%;
    -webkit-mask-repeat: no-repeat;
    mask-repeat: no-repeat;
}

#chat .mes .avatar img {
    width: 100% !important;
    height: 100% !important;
    object-fit: cover !important;
    object-position: center center !important;
    display: block !important;
    border-radius: 0 !important;
    transform: rotate(30deg);
}

/* 顶部文案 */
#chat .mes::after {
    content: '';
    position: absolute;
    top: 60px;
    z-index: 2;
    left: 50%;
    transform: translateX(-50%);
    font-family: 'Courier New', Courier, monospace;
    font-size: 1.6em;
    font-weight: bold;
    white-space: nowrap;
    overflow: hidden;
    width: 10ch;
}

#chat .mes:not([is_user="true"])::after {
    content: '自定义文本'; /* 角色自定义文本处 */
    animation: none;
}

#chat .mes[is_user="true"]::after {
    content: '自定义文本'; /* 用户自定义文本处 */
    animation: none;
}

#chat .mes:not([is_user="true"]):not(:hover)::after {
    width: 10ch;
    animation: none;
}

#chat .mes:not([is_user="true"]):hover::after {
    width: 0;
    animation: TypingAnimation 2s steps(10, end) forwards;
    animation-delay: 0.05s;
}

#chat .mes[is_user="true"]:not(:hover)::after {
    width: 10ch;
    animation: none;
}

#chat .mes[is_user="true"]:hover::after {
    width: 0;
    animation: TypingAnimation 2s steps(10, end) forwards;
    animation-delay: 0.05s;
}

@keyframes TypingAnimation {
    from { width: 0; }
    to { width: 10ch; }
}

/* 顶部背景图片 */
#chat .mes::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 160px;
    background-repeat: no-repeat;
    background-position: center top;
    background-size: cover !important;
    border-top-left-radius: 12px !important;
    border-top-right-radius: 12px !important;
    z-index: 0;
}

#chat .mes:not([is_user="true"])::before {
    background-image: url('');
}

#chat .mes[is_user="true"]::before {
    background-image: url('');
}

/* 消息底部信息 */
#chat .mes .mesIDDisplay,
#chat .mes .mes_timer,
#chat .mes .tokenCounterDisplay {
    position: absolute !important;
    bottom: -15px !important;
    font-size: 12px !important;
    opacity: 0.8 !important;
    font-family: monospace !important;
    white-space: nowrap !important;
}

#chat .mes:not([is_user="true"]) .mesIDDisplay {
    left: 20px !important;
}
#chat .mes:not([is_user="true"]) .mes_timer {
    left: 55px !important;
}
#chat .mes:not([is_user="true"]) .tokenCounterDisplay {
    left: 105px !important;
}

#chat .mes[is_user="true"] .tokenCounterDisplay {
    right: 20px !important;
}
#chat .mes[is_user="true"] .mesIDDisplay {
    right: 45px !important;
}
#chat .mes[is_user="true"] .mes_timer {
    display: none !important;
}

/* 选择框样式 */
select {
    -webkit-appearance: none !important;
    -moz-appearance: none !important;
    appearance: none !important;
    background-image: none !important;
    background-color: #F1F8E9 !important;
    transition: background-color 0.2s ease !important;
    height: auto !important;
    padding: 2px 12px !important;
    border: none !important;
    border-radius: 4px !important;
    box-shadow: none !important;
    outline: none !important;
    line-height: 1.5 !important;
}

select:hover,
select:focus {
    background-color: #DCEDC8 !important;
    animation: none !important;
    text-shadow: none !important;
}

/* 选择框颜色切换 */
select {
    background-color: #F1F8E9 !important;
}
select:hover,
select:focus {
    background-color: #DCEDC8 !important;
}

select#themes,
select#chat_display {
    background-color: #DCEDC8 !important;
}

select#themes:hover,
select#themes:focus,
select#chat_display:hover,
select#chat_display:focus {
    background-color: #F1F8E9 !important;
}

/* 时间戳上方文本 */
.mes:not([is_user="true"]) .mes_block::after {
    content: '自定义文本' !important; /* 角色自定义文本处 */
    position: absolute !important;
    bottom: 28px !important;
    right: 10px !important;
    font-size: 1em !important;
}

.mes[is_user="true"] .mes_block::after {
    content: '自定义文本' !important; /* 用户自定义文本处 */
    position: absolute !important;
    bottom: 28px !important;
    left: 10px !important;
    font-size: 1em !important;
}

/* 时间戳位置 */
.mes .ch_name .timestamp {
    position: absolute !important;
    bottom: 8px !important;
    font-size: 0.8em !important;
}

.mes:not([is_user="true"]) .timestamp {
    right: 10px !important;
}

.mes[is_user="true"] .timestamp {
    left: 10px !important;
}

/* 底栏 */
#form_sheld {
  position: absolute;
  bottom: 20px;
}

#send_form {
  width: 90%;
}

.last_mes {
  margin-bottom: 150px !important;
}

#send_form, body.no-blur #send_form {
  border-radius: 22px;
  background-color: #ffffff !important;
  padding: 10px 15px;
  border: 2px solid transparent;
  box-shadow: inset 0 0 0 2px #ADBE87;
}

#rightSendForm, #leftSendForm {
  gap: 5px;
}

#send_textarea {
  clip-path: none !important;
}

#send_textarea {
  border: none;
}

#send_form:has(#send_textarea:focus-visible) {
  outline: none;
}

#qr--bar > .qr--buttons .qr--button {
  filter: none;
}

/* 底栏图标 */
#options_button::before,
#extensionsMenuButton::before,
#send_but::before,
#quick-reply-rocket-button > i {
    display: none !important;
}

#options_button,
#extensionsMenuButton,
#send_but,
#quick-reply-rocket-button {
    width: 32px;
    height: 32px;
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    transition: transform 0.2s ease;
    font-size: 0;
    border: none;
    background-color: transparent;
}

#options_button:hover,
#extensionsMenuButton:hover,
#send_but:hover,
#quick-reply-rocket-button:hover {
    transform: scale(1.1);
}

#options_button { background-image: url('https://p.sda1.dev/27/538693b9508959dafbb7a3792a6caff0/无标题300_20251005182510.png'); }
#extensionsMenuButton { background-image: url('https://p.sda1.dev/27/3f4529d463ad75aadeb113b6f4890e52/无标题300_20251005182442.png'); }
#send_but { background-image: url('https://p.sda1.dev/27/b3a2b7e7af60b90c4f946c6604d236dc/无标题300_20251005182422.png'); }
}

/* 输入框提示词 */
#nonQRFormItems {
    position: relative;
}

#send_textarea::placeholder {
    color: transparent !important;
    text-shadow: none !important;
}

#nonQRFormItems:has(#send_textarea:placeholder-shown)::before {
    content: ".☘︎ ݁˖春日の便り₊ ⊹❀";
    color: #ADBE87;
    position: absolute;
    left: 50%;
    top: 50%;
    transform: translate(-50%, -50%);
    font-style: italic;
    font-size: 0.6em;
    pointer-events: none;
    z-index: 10;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: calc(100% - 30px);
}

#chat .mes .mes_block {
   padding: 0px 20px 50px 20px !important;
    overflow: visible !important;
}

/* 昵称 */
#chat .mes[is_user="false"] .mesAvatarWrapper { justify-content: flex-start; }
#chat .mes[is_user="false"] .ch_name { margin-left: 65px !important; text-align: left !important; }
#chat .mes[is_user="false"] .ch_name .name_text { text-align: left !important; }
#chat .mes[is_user="true"] .mesAvatarWrapper { justify-content: flex-end !important; }
#chat .mes[is_user="true"] .ch_name {
    margin-right: 65px !important; text-align: right !important; width: auto !important;
    max-width: none !important; white-space: nowrap !important; overflow: visible !important;
    direction: rtl; unicode-bidi: bidi-override;
}

#chat .mes[is_user="false"] .ch_name .name_text::after {
    content: "自定义文本"; /* 角色自定义文本处 */
    display: block !important; font-size: 12px !important;
    font-weight: normal !important; opacity: 0.8 !important;
    margin-top: 4px !important; line-height: 1.3 !important; text-align: left !important;
}

#chat .mes[is_user="true"] .ch_name .name_text::after {
    content: "自定义文本"; /* 用户自定义文本处 */
    display: block !important; font-size: 12px !important;
    font-weight: normal !important; opacity: 0.8 !important;
    margin-top: 4px !important; line-height: 1.3 !important; text-align: right !important;
}

#chat .mes .ch_name .name_text {
    margin-top: -88px !important;
}

/* 导航栏 */
#top-settings-holder {
    background-size: 100% 100%;
    background-position: center;
    background-color: 十六进制背景色;
    box-shadow: none;
}

.drawer-icon.fa-fw::before {
    content: '' !important;
    font-size: 0 !important;
}

.drawer-icon.fa-fw {
    width: 35px;
    height: 40px;
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    transition: transform 0.3s ease;
}

.drawer-icon.fa-fw:hover {
    transform: scale(1.1);
}

#ai-config-button .drawer-icon { background-image: url('https://p.sda1.dev/27/120ef188ae2f30336854c7ffdecdabf4/无标题299_20251007173524.png'); }
#sys-settings-button .drawer-icon { background-image: url('https://p.sda1.dev/27/fc840c77d37aa597f3d6f7a7d4ba05f0/无标题299_20251007173620.png'); }
#advanced-formatting-button .drawer-icon { background-image: url('https://p.sda1.dev/27/120ef188ae2f30336854c7ffdecdabf4/无标题299_20251007173524.png'); }
#WI-SP-button .drawer-icon { background-image: url('https://p.sda1.dev/27/fc840c77d37aa597f3d6f7a7d4ba05f0/无标题299_20251007173620.png'); }
#user-settings-button .drawer-icon { background-image: url('https://p.sda1.dev/27/120ef188ae2f30336854c7ffdecdabf4/无标题299_20251007173524.png'); }
#logo_block .drawer-icon { background-image: url('https://p.sda1.dev/27/fc840c77d37aa597f3d6f7a7d4ba05f0/无标题299_20251007173620.png'); }
#extensions-settings-button .drawer-icon { background-image: url('https://p.sda1.dev/27/120ef188ae2f30336854c7ffdecdabf4/无标题299_20251007173524.png'); }
#persona-management-button .drawer-icon { background-image: url('https://p.sda1.dev/27/fc840c77d37aa597f3d6f7a7d4ba05f0/无标题299_20251007173620.png'); }
#rightNavHolder .drawer-icon { background-image: url('https://p.sda1.dev/27/120ef188ae2f30336854c7ffdecdabf4/无标题299_20251007173524.png'); }

/* 滑块按钮 */
input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    width: 40px;
    height: 40px;
    background: url('https://p.sda1.dev/27/cc98eb9a7094555ff2d5b31604455045/无标题299_20251007175944.png') no-repeat center center;
    background-size: contain;
    cursor: pointer;
    box-shadow: none !important;
    border: none !important;
    background-color: transparent !important;
    margin-top: -0px;
    transition: transform .2s ease;
}

/* 消息按钮 */
#chat .mes .mes_buttons {
    position: absolute !important; filter: none !important; z-index: 10 !important;
}

#chat .mes[is_user="false"] .mes_buttons { top: -45px !important; right: 15px !important; }
#chat .mes[is_user="true"] .mes_buttons { top: -45px !important; left: 15px !important; }

#chat .mes .mes_edit_buttons {
    position: absolute !important; top: -20px !important; right: 10px !important;
    z-index: 20 !important; transform: translateY(0) !important;
}

#chat .mes[is_user="true"] .mes_edit_buttons {
    right: 72px !important;
}

#chat .mes[is_user="false"] .mes_edit_buttons {
    left: 72px !important;
}

.drawer-content {
  border-radius: 0 0 0 0 !important;
}

/* 复选框 */
input[type="checkbox"]:checked::before {
  width: 13px;
  height: 13px;
  box-shadow: none;
  background: url(https://p.sda1.dev/27/c4e4b8c36955d40c7a427a07b61b17cb/无标题301_20251007191557.png);
  background-size: contain;
  background-repeat: no-repeat;
  cursor: pointer;
  clip-path: none;
}

/* 输入框 */
input:not(input[type="range"], input[type='checkbox']) {
  background-color: white !important;
  border: none;
}

.inline-drawer-icon::before {
  display: none;
}

/* 文本编辑框 */
textarea[data-for="description_textarea"],
textarea[data-for="firstmessage_textarea"],
#curEditTextarea,
.edit_textarea {
  background-color: #F1F8E9 !important;
}

#customCSS,
#firstmessage_textarea,
#description_textarea,
#curEditTextarea,
.edit_textarea {
  background-color: #F1F8E9 !important;
}

textarea[data-for="customCSS"] {
background-color: #F1F8E9 !important;
}

/* UI元素背景 */
textarea[data-for="customCSS"],
code,
#wiTopBlock .inline-drawer-content,
.text_pole,
input[type="checkbox"] {
    background-color: #F1F8E9 !important;
}

.prompt-manager-inspect-action {
    color: #798874 !important;
}

code { color: #798874 !important; }

/* 思维链 */
.mes_reasoning_header_title::before {
    content: "‎₊𐙚ﾟ⁺正在思考中⸝⋆︎*‎";
    font-size: var(--mainFontSize);
}

.mes_reasoning_header_title {
    font-size: 0;
}

.mes_reasoning_arrow {
    display: none !important;
}

/* 标题框 */
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#user-settings-block h4,
.standoutHeader {
  background-color: #B9D19B;
  background-image: none;
  border: none;
  border-radius: 4px;
  padding: 3px 15px;
  box-shadow: 1px 2px 4px rgba(0, 0, 0, 0.4);
  text-shadow: 1px 1px 2px rgba(0, 0, 0, 0.3);
}

/* 搜索框 */
#settingsSearch {
    background-color: #DCEDC8!important;
}

.regex-script-container {
    padding-right: 40px;
}

/* 删除消息勾选框 */
#chat .mes .del_checkbox {
    position: absolute !important;
    top: 15px !important;
}

#chat .mes:not([is_user="true"]) .del_checkbox {
    left: 15px !important;
    right: auto !important;
}

#chat .mes[is_user="true"] .del_checkbox {
    right: 15px !important;
    left: auto !important;
}

/* 思维链背景 */
#chat .mes .mes_reasoning_header {
    background-color: #B9D19B !important;
}

#chat .mes .mes_reasoning_header .mes_reasoning_header_title::before {
    color: #F7FFEE !important;
}

details.mes_reasoning_details .mes_reasoning p {
  margin: 5px 0;
  width: 100%;
  text-align: justify;
}

/* 思维链与编辑框背景 */
#chat .mes .reasoning_edit_textarea {
    background-color: #F1F8E9 !important;
}

.drawer-content input[type="range"] + input,
.drawer-content input[type="number"] {
    background-color: #DDEDC8 !important;
    border: none !important;
}

/* 滑动条 */
input[type="range"],
input[type="range"]:focus,
input[type="range"]:active {
  -webkit-appearance: none !important;
  appearance: none !important;
  width: 100%;
  border: none !important;
  background: transparent !important;
  outline: none !important;
  padding: 0;
  margin: 0;
  box-shadow: none !important;
}

input[type="range"]::-webkit-slider-runnable-track {
  width: 100%;
  height: 2px;
  background-color: #97B96E !important;
  border: none;
  cursor: pointer;
  border-radius: 1px !important;
}

input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    width: 40px;
    height: 40px;
    background: url('https://p.sda1.dev/27/cc98eb9a7094555ff2d5b31604455045/无标题299_20251007175944.png') no-repeat center center;
    background-size: contain;
    cursor: pointer;
    box-shadow: none !important;
    border: none !important;
    background-color: transparent !important;
    margin-top: -22px !important;
    transition: transform .2s ease;
}

/* 主输入框 */
#send_textarea {
  background-color: #F1F8E9 !important;
  border-radius: 6px !important;
  padding: 8px 10px !important;
}

/* 最后一条消息间距 */
#chat .mes:last-child {
  margin-bottom: 100px !important;
}

/* 设置项间距 */
div:has(#aux_field) {
  margin-bottom: 5px !important;
}

/* 心理活动文本 */
#chat .mes .mes_text em {
  border-bottom: 1px dashed #B9D19B !important;
  padding-bottom: 1px;
}

/* 引用文本 */
#chat .mes .mes_text q {
  background-color: rgba(185, 209, 155, 0.1) !important;
  border-radius: 3px !important;
  quotes: none;
}

/* 信件 */
#chat .mes:not([is_user="true"]) .mes_text {
  position: relative !important;
  padding-top: 55px !important;
}

#chat .mes:not([is_user="true"]) .mes_text::before {
  content: "自定义文本："; /* 角色自定义文本处 */
  position: absolute;
  top: 0;
  left: 0;
  font-size: 1.2em;
  line-height: 1.6;
}

#chat .mes:not([is_user="true"]) .mes_text::after {
  content: "　　自定义文本"; /* 角色自定义文本处 */
  position: absolute;
  top: 2em;
  left: 0;
  line-height: 1.6;
  white-space: pre-wrap;
}
